// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.nio.ByteBuffer;
import java.util.Random;

import org.junit.jupiter.api.Test;
import org.lwjgl.system.MemoryUtil;

class ScanBenchmarkTest {

	@Test
	void byteAtATimeBaselineMatchesNativeDecoder() {
		long[] boundaries = {
				0L, 240L, 241L, 2_287L, 2_288L, 67_823L, 67_824L,
				(1L << 24) - 1L, 1L << 24, (1L << 32) - 1L, 1L << 32,
				(1L << 48) - 1L, 1L << 48, Long.MAX_VALUE
		};
		ByteBuffer encoded = MemoryUtil.memAlloc(Varint.ENCODED_LONG_MAX.length);
		try {
			for (long value : boundaries) {
				assertDecoders(encoded, value);
			}
			Random random = new Random(20260720L);
			for (int sample = 0; sample < 10_000; sample++) {
				assertDecoders(encoded, random.nextLong() & Long.MAX_VALUE);
			}
		} finally {
			MemoryUtil.memFree(encoded);
		}
	}

	private static void assertDecoders(ByteBuffer encoded, long value) {
		encoded.clear();
		Varint.writeUnsigned(encoded, value);
		encoded.flip();
		long address = MemoryUtil.memAddress(encoded);
		assertThat(ScanBenchmark.readUnsignedByteAtATime(address)).isEqualTo(value);
		assertThat(Varint.readUnsigned(address)).isEqualTo(value);
	}
}
